#!/bin/sh
# Robust startup script for Render deployment
# Step 1: Ensure all columns exist (handles pre-existing DB from db push era)
# Step 2: Resolve any failed migrations
# Step 3: Run migrate deploy
# Step 4: Start the application

echo "[Start] Step 1: Ensuring all columns exist in database..."
npx prisma db execute --file scripts/ensure-columns.sql --schema prisma/schema.prisma
if [ $? -ne 0 ]; then
  echo "[Start] WARNING: ensure-columns.sql had errors, continuing anyway..."
fi
echo "[Start] Column check complete."

echo "[Start] Step 2: Resolving any previously failed migrations..."
MIGRATIONS="0_init 20260401000000_add_expenses 20260401000001_add_employee_portal 20260402000000_expense_payment_fields 20260402000001_add_unverified_client_name 20260402100000_expense_source_field 20260402100000_p0_02_user_employee_relation 20260402100001_p1_01_worklog_add_project_id 20260402100002_p1_03_company_profile_add_company_id 20260402100003_p2_03_worklog_matched_ot_rate_to_decimal 20260402200000_add_contracts 20260402_phase2_bq_vo 20260403000001_add_cert_photos 20260403100000_project_contract_on_delete_restrict 20260403120000_unify_rate_card_rate_fields 20260403200000_phase3_payment_applications 20260403300000_phase4_phase6_payments_retention 20260403400000_phase5_invoices 20260403500000_phase7_phase8_expense_expansion 20260404000000_phase9_bank_reconciliation 20260404100000_fleet_rate_card_day_night_rate 20260404200000_add_contract_id_to_work_log 20260404300000_rate_card_fields_and_ot_tables 20260404400000_add_equipment_number_to_rate_cards 20260404500000_add_missing_fleet_subcon_columns 20260405100000_add_mid_shift_fields 20260405200000_rename_vehicle_to_machine 20260405300000_add_contract_id_to_fleet_rate_cards 20260406000000_add_client_contract_no 20260406100000_add_company_id_to_work_logs_payrolls 20260407000000_add_short_name_to_partners 20260407100000_remove_short_name_from_partners 20260407200000_add_verification_module 20260408000000_rename_vehicle_type_to_machine_type 20260408100000_add_client_contract_no_to_projects 20260408200000_invoice_enhancements 20260409000000_verification_phase1_supplement 20260410000000_add_ocr_base64_and_confirmed_data 20260411000000_add_employee_photo_base64 20260411100000_add_vehicle_extra_fields 20260411200000_add_user_can_company_clock 20260412000000_wa_order_modification_tracking 20260413000000_wa_order_item_type 20260414000000_make_employee_company_id_optional 20260415000000_add_employee_mpf_applied 20260420000000_add_page_permissions 20260420000001_add_work_log_source 20260421000000_add_worklog_location_new_and_ai_parsed"

for migration in $MIGRATIONS; do
  npx prisma migrate resolve --applied "$migration" 2>/dev/null && echo "[Start] Resolved: $migration" || true
done

echo "[Start] Step 3: Running migrate deploy..."
npx prisma migrate deploy

echo "[Start] Step 4: Starting application..."
exec node dist/src/main
